// ===== 貼り付けから一括取り込み =====
let importedData=null;

function copyPrompt(){
  const t=$('aiPrompt');
  t.select();
  navigator.clipboard.writeText(t.value).then(()=>{
    const btn=event.target;
    const orig=btn.textContent;
    btn.textContent='✓コピー済';
    btn.style.background='#059669';
    setTimeout(()=>{btn.textContent=orig;btn.style.background='#0284c7';},1500);
  }).catch(()=>{
    alert('copy failed');
  });
}

function parseRawText(){
  const text=$('rawText').value.trim();
  if(!text){
    showOcrErr('テキストが空です。AIの返答を貼り付けてください。');
    return;
  }
  
  try{
    const lines=text.split('\n').map(l=>l.trim()).filter(l=>l);
    const data={courseName:'',players:[],pars:[],hdps:[]};
    
    lines.forEach(line=>{
      if(line.startsWith('GOLF=')){
        data.courseName=line.substring(5).trim();
      }
      if(line.startsWith('COURSE_OUT=')){
        data.courseOut=line.substring(11).trim();
      }
      if(line.startsWith('COURSE_IN=')){
        data.courseIn=line.substring(10).trim();
      }else if(line.match(/^P[1-4]=/)){
        const parts=line.substring(3).split(',').map(s=>s.trim());
        if(parts.length>=2){
          const name=parts[0];
          const total=parseInt(parts[1])||null;
          const holes=parts.slice(2,20).map(s=>parseInt(s)||null);
          data.players.push({name,totalScore:total,holes});
        }
      }else if(line.startsWith('PAR=')){
        data.pars=line.substring(4).split(',').map(s=>parseInt(s.trim())||0);
      }else if(line.startsWith('HDP=')){
        data.hdps=line.substring(4).split(',').map(s=>parseInt(s.trim())||0);
      }
    });
    
    if(data.players.length===0){
      showOcrErr('プレーヤー情報が見つかりません。\n形式を確認してください（例: P1=名前,合計,1H,2H...）');
      return;
    }
    
    // holeInfo構築
    data.holeInfo=[];
    for(let i=0;i<18;i++){
      data.holeInfo.push({hole:i+1,par:data.pars[i]||0,hdp:data.hdps[i]||0});
    }
    
    importedData=data;
    if(data.courseName)$('cname').value=data.courseName;
    
    // フラグをリセットして毎回反映できるようにする
    importedData._appliedToPlayers=false;
    importedData._appliedToHoles=false;
    
    // プレーヤー情報をスタートページに即座に反映
    data.players.slice(0,4).forEach((p,i)=>{
      if($('nm'+i)&&p.name)$('nm'+i).value=p.name;
      if($('sc'+i)&&p.totalScore)$('sc'+i).value=p.totalScore;
    });
    updHC();
    
    // Par・HDPがある場合は自動でコース名入力欄を表示
    var registerBtn=$('registerCourseBtn');
    var inputArea=$('courseNameInputArea');
    var golfNameEl=$('importGolfName');
    if(data.holeInfo&&data.holeInfo.length>0){
      if(registerBtn)registerBtn.style.display='none';
      if(golfNameEl)golfNameEl.textContent=data.courseName||'';
      if($('importCourseNameOut'))$('importCourseNameOut').value=data.courseOut||'';
      if($('importCourseNameIn'))$('importCourseNameIn').value=data.courseIn||'';
      if(inputArea)inputArea.style.display='block';
    } else {
      if(registerBtn)registerBtn.style.display='none';
      if(inputArea)inputArea.style.display='none';
    }
    
    showOcrOk('取り込み成功！\nゴルフ場: '+(data.courseName||'(未入力)')+'\nプレーヤー: '+data.players.map(function(p){return p.name;}).join('・')+'\n\n内容を確認して「次へ →」を押してください。');
    
  }catch(e){
    showOcrErr('取り込みエラー: '+e.message+'\n形式を確認してください。');
  }
}

function registerCourseFromImport(){
  if(!importedData||!importedData.holeInfo)return;
  var gn=importedData.courseName||'';
  var btn=$('registerCourseBtn');
  if(!btn)return;
  // コース名入力欄を表示
  btn.style.display='none';
  var inputArea=$('courseNameInputArea');
  if(inputArea){
    inputArea.style.display='block';
    $('importCourseName').value='';
    $('importGolfName').textContent=gn;
  }
}

function saveImportedCourse(){
  if(!importedData||!importedData.holeInfo)return;
  var gn=importedData.courseName||'';
  var cnOut=$('importCourseNameOut').value.trim();
  var cnIn=$('importCourseNameIn').value.trim();
  if(!cnOut&&!cnIn){showConfirmDialog('ゴルフ場名とコース名を入力してください', function(){});return;}
  var list=getCourses();
  // 前半（1〜9H）を登録
  if(cnOut){
    var holesOut=importedData.holeInfo.filter(function(h){return h.hole<=9;}).map(function(h){
      return {hole:h.hole,par:h.par||4,hdp:h.hdp||h.hole};
    });
    list.push({id:Date.now(),golfName:gn,courseName:cnOut,start:'out',holes:holesOut});
  }
  // 後半（10〜18H）を登録（1〜9Hとして扱う）
  if(cnIn){
    var holesIn=importedData.holeInfo.filter(function(h){return h.hole>=10;}).map(function(h){
      return {hole:h.hole-9,par:h.par||4,hdp:h.hdp||h.hole-9};
    });
    list.push({id:Date.now()+1,golfName:gn,courseName:cnIn,start:'in',holes:holesIn});
  }
  saveCourseList(list);
  $('courseNameInputArea').style.display='none';
  var saved=[];
  if(cnOut)saved.push(cnOut);
  if(cnIn)saved.push(cnIn);
  alert('saved: '+saved.join(' / '));
}

function cancelImportedCourse(){
  var btn=$('registerCourseBtn');
  var inputArea=$('courseNameInputArea');
  if(btn)btn.style.display='block';
  if(inputArea)inputArea.style.display='none';
}

