function buildHoleTabBar(){
  var bar=document.getElementById('holeTabBar');
  if(!bar)return;
  updateHoleTabBar();
}

function updateHoleTabBar(){
  var bar=document.getElementById('holeTabBar');
  if(!bar)return;
  var rounds=getRoundHoles();
  var idx=getRoundIndex(_currentHole);
  // 前後1ホール（合計3ホール）だけ表示
  var visible=[];
  if(idx===0){
    visible=[rounds[0],rounds[1],rounds[2]];
  } else if(idx===17){
    visible=[rounds[15],rounds[16],rounds[17]];
  } else {
    visible=[rounds[idx-1],rounds[idx],rounds[idx+1]];
  }
  var html='';
  visible.forEach(function(h){
    var isActive=h===_currentHole;
    html+='<button type="button" onclick="showHole('+h+')" id="htab_'+h+'" style="flex:1;height:44px;border:none;border-radius:8px;font-size:16px;font-weight:700;cursor:pointer;background:'+(isActive?'#22c55e':'rgba(255,255,255,0.15)')+';color:'+(isActive?'#000':'#fff')+';">'+h+'</button>';
  });
  bar.innerHTML=html;
}

